import React, { useState, useEffect } from 'react';
import { FaUsers, FaBook, FaBuilding, FaChalkboardTeacher, FaCalendar } from 'react-icons/fa';
import { studentAPI, subjectAPI, hallAPI, teacherAPI, scheduleAPI } from '../services/api';
import { toast } from 'react-toastify';

const Dashboard = () => {
  const [stats, setStats] = useState({
    students: 0,
    subjects: 0,
    halls: 0,
    teachers: 0,
    exams: 0,
  });

  const [scheduleStats, setScheduleStats] = useState(null);

  useEffect(() => {
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      const [studentsRes, subjectsRes, hallsRes, teachersRes, scheduleRes] = await Promise.all([
        studentAPI.getAll(),
        subjectAPI.getAll(),
        hallAPI.getAll(),
        teacherAPI.getAll(),
        scheduleAPI.getStats(),
      ]);

      setStats({
        students: studentsRes.data.length,
        subjects: subjectsRes.data.length,
        halls: hallsRes.data.length,
        teachers: teachersRes.data.length,
        exams: scheduleRes.data.totalExams || 0,
      });

      setScheduleStats(scheduleRes.data);
    } catch (error) {
      console.error('Error fetching stats:', error);
      toast.error('Failed to load dashboard data');
    }
  };

  const StatCard = ({ icon, title, value, color }) => (
    <div className={`bg-white rounded-lg shadow-md p-6 card-hover border-l-4 ${color}`}>
      <div className="flex items-center justify-between">
        <div>
          <p className="text-gray-600 text-sm font-medium mb-1">{title}</p>
          <p className="text-3xl font-bold text-gray-800">{value}</p>
        </div>
        <div className={`text-4xl opacity-20`}>{icon}</div>
      </div>
    </div>
  );

  return (
    <div className="space-y-8">
      <div className="bg-white rounded-lg shadow-md p-6">
        <h1 className="text-3xl font-bold text-gray-800 mb-2">Dashboard</h1>
        <p className="text-gray-600">Welcome to Smart Exam Scheduler System</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-6">
        <StatCard
          icon={<FaUsers />}
          title="Total Students"
          value={stats.students}
          color="border-blue-500"
        />
        <StatCard
          icon={<FaBook />}
          title="Total Subjects"
          value={stats.subjects}
          color="border-green-500"
        />
        <StatCard
          icon={<FaBuilding />}
          title="Total Halls"
          value={stats.halls}
          color="border-yellow-500"
        />
        <StatCard
          icon={<FaChalkboardTeacher />}
          title="Total Teachers"
          value={stats.teachers}
          color="border-purple-500"
        />
        <StatCard
          icon={<FaCalendar />}
          title="Scheduled Exams"
          value={stats.exams}
          color="border-red-500"
        />
      </div>

      {scheduleStats && scheduleStats.totalExams > 0 && (
        <div className="bg-white rounded-lg shadow-md p-6">
          <h2 className="text-2xl font-bold text-gray-800 mb-4">Schedule Overview</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            <div className="bg-blue-50 rounded-lg p-4">
              <p className="text-gray-600 text-sm">Total Exam Days</p>
              <p className="text-2xl font-bold text-blue-600">{scheduleStats.totalDays}</p>
            </div>
            <div className="bg-green-50 rounded-lg p-4">
              <p className="text-gray-600 text-sm">Departments</p>
              <p className="text-2xl font-bold text-green-600">{scheduleStats.totalDepartments}</p>
            </div>
            <div className="bg-yellow-50 rounded-lg p-4">
              <p className="text-gray-600 text-sm">Halls Used</p>
              <p className="text-2xl font-bold text-yellow-600">{scheduleStats.totalHalls}</p>
            </div>
            <div className="bg-purple-50 rounded-lg p-4">
              <p className="text-gray-600 text-sm">Date Range</p>
              <p className="text-sm font-semibold text-purple-600">
                {scheduleStats.dates && scheduleStats.dates.length > 0 
                  ? `${scheduleStats.dates[0]} to ${scheduleStats.dates[scheduleStats.dates.length - 1]}`
                  : 'N/A'}
              </p>
            </div>
          </div>
        </div>
      )}

      <div className="bg-gradient-to-r from-blue-500 to-purple-600 rounded-lg shadow-md p-8 text-white">
        <h2 className="text-2xl font-bold mb-3">Quick Actions</h2>
        <p className="mb-6">Get started with scheduling exams</p>
        <div className="flex flex-wrap gap-4">
          <a href="/students" className="bg-white text-blue-600 px-6 py-2 rounded-lg font-semibold hover:bg-gray-100 transition">
            Manage Students
          </a>
          <a href="/subjects" className="bg-white text-blue-600 px-6 py-2 rounded-lg font-semibold hover:bg-gray-100 transition">
            Manage Subjects
          </a>
          <a href="/generate" className="bg-yellow-400 text-gray-800 px-6 py-2 rounded-lg font-semibold hover:bg-yellow-300 transition">
            Generate Schedule
          </a>
          <a href="/schedule" className="bg-green-500 text-white px-6 py-2 rounded-lg font-semibold hover:bg-green-600 transition">
            View Schedule
          </a>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
